def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = np.exp(-usage_ratio)
        if usage_ratio > 2:
            priority += (usage_ratio - 2) ** 3 * 500
        elif usage_ratio > 1.2:
            priority += (usage_ratio - 1) ** 2 * 300
        elif usage_ratio == 1:
            priority += 250
        else:
            try:
                log_val = np.log(max(1 - usage_ratio, 1e-15))
            except FloatingPointError:
                log_val = -np.inf
            if log_val < -3:
                priority += -log_val * 15
            elif log_val < -1.5:
                priority += -log_val * 9
            else:
                priority += -log_val * 4
            extra_factor = 0
            for j in range(1, 8):
                power = usage_ratio ** j
                if power < 0.3:
                    extra_factor += power * 15 / j
                    if j % 3 == 0:
                        extra_factor += 2 * j
                else:
                    extra_factor += (1 - power) * 10 / (j + 1)
                    if j == 5 and usage_ratio > 0.75:
                        extra_factor += 8
            priority += extra_factor
        if capacity < 0.01:
            priority += 120
            if usage_ratio > 0.8:
                priority += 60
            elif usage_ratio < 0.2:
                priority -= 30
        elif capacity < 0.25:
            priority += 40
            if usage_ratio > 0.9:
                priority += 35
            elif usage_ratio < 0.15:
                priority -= 15
        elif capacity < 0.8:
            if usage_ratio < 0.3:
                priority -= 15
            elif usage_ratio > 0.65:
                priority += 45
            else:
                priority += 15
        else:
            if usage_ratio < 0.15:
                priority -= 20
            elif usage_ratio > 0.85:
                priority += 50
            else:
                priority += 8
        proximity_score = 0
        if int(capacity * 1000) % 5 == 0:
            proximity_score += 7
        if int(capacity * 10) % 4 == 0:
            proximity_score -= 5
        if int(capacity * 100) % 11 == 0:
            proximity_score += 9
        for k in range(1, 6):
            diff = abs(usage_ratio - k / 6)
            if diff < 0.03:
                proximity_score += 14 / k
            elif diff < 0.08:
                proximity_score += 7 / k
            else:
                proximity_score -= 1 / k
        for m in range(1, 5):
            mod_check = (capacity * 1000) % (m + 3)
            if mod_check == 0:
                proximity_score += m * 3
            elif mod_check == 2:
                proximity_score -= m * 1.5
        if int(capacity) % 2 == 1:
            proximity_score += 5
        priority += proximity_score
        if usage_ratio < 0.03:
            for n in range(1, 5):
                priority -= n * 4
        elif usage_ratio > 0.97:
            for p in range(1, 5):
                priority += p * 6
        sin_adj = np.sin(usage_ratio * np.pi * 4) * 10
        cos_adj = np.cos(capacity * np.pi * 3) * 7
        priority += sin_adj + cos_adj
        if capacity > 0.5 and usage_ratio < 0.6:
            temp_sum = 0
            for q in range(1, 10):
                temp_sum += ((usage_ratio * q) % 1) * (capacity / q)
            priority += temp_sum * 2
        elif capacity <= 0.5 and usage_ratio > 0.4:
            temp_prod = 1
            for r in range(1, 5):
                temp_prod *= abs(np.sin(capacity * r + usage_ratio * r))
            priority += temp_prod * 50
        priorities[i] = priority
    return priorities
